uint64_t Chassis::_computeHash(const __lcm_hash_ptr *p)
{
    const __lcm_hash_ptr *fp;
    for(fp = p; fp != NULL; fp = fp->parent)
        if(fp->v == Chassis::getHash)
            return 0;
    const __lcm_hash_ptr cp = { p, Chassis::getHash };

    uint64_t hash = 0x88932f505789bb4dLL +
         lcm_interface::Header::_computeHash(&cp);

    return (hash<<1) + ((hash>>63)&1);
}

